--
-- Table structure for table `environment_monitor`
--
DROP TABLE IF EXISTS `environment_monitor`;
CREATE TABLE `environment_monitor` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `zone` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '区域',
  `temperature` double DEFAULT NULL,
  `humidity` double DEFAULT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'NORMAL' COMMENT '状态: NORMAL/WARNING/CRITICAL',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3117 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='环境监测数据表';

