DROP TABLE IF EXISTS `environment_threshold`;
CREATE TABLE `environment_threshold` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `zone` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '区域',
  `temp_min` double DEFAULT NULL,
  `temp_max` double DEFAULT NULL,
  `humidity_min` double DEFAULT NULL,
  `humidity_max` double DEFAULT NULL,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `zone` (`zone`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='环境预警阈值配置表';

